import machine
import umqtt.simple
import time

# WiFi credentials
WIFI_SSID = 'your_ssid'
WIFI_PASSWORD = 'your_password'

# MQTT broker settings
MQTT_BROKER_IP = 'your_broker_ip'

# Create an MQTT client object
client_id = 'esp32_sensor'
mqtt_client = umqtt.simple.MQTTClient(client_id, MQTT_BROKER_IP)

# Connect to WiFi
wlan = machine.WIFINetwork(ssid=WIFI_SSID, password=WIFI_PASSWORD)
wlan.connect()

# Connect to MQTT broker
mqtt_client.connect()

# Get temperature sensor reading
sensor = machine.ADC(4)
while True:
    temperature = sensor.read() * (3.3 / 4095) * 100
    
    # Publish temperature reading to MQTT topic
    mqtt_client.publish('sensors/temp', str(temperature))
    
    time.sleep(5)